package com.grl.component.schema;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import com.grl.component.asg.OntologyConstants;
import java.util.Optional;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.semanticweb.owlapi.apibinding.OWLManager;
import org.semanticweb.owlapi.model.IRI;
import org.semanticweb.owlapi.model.OWLAnnotationProperty;
import org.semanticweb.owlapi.model.OWLClass;
import org.semanticweb.owlapi.model.OWLClassExpression;
import org.semanticweb.owlapi.model.OWLDataFactory;
import org.semanticweb.owlapi.model.OWLNamedIndividual;
import org.semanticweb.owlapi.model.OWLObjectProperty;
import org.semanticweb.owlapi.model.OWLOntology;
import org.semanticweb.owlapi.model.OWLOntologyCreationException;
import org.semanticweb.owlapi.model.OWLOntologyManager;

/**
 * Unit tests for TaxonomyPatternDetector.
 * Tests detection of taxonomy patterns A, B, C, and D from OWL class expressions.
 */
class TaxonomyPatternDetectorTest {

  private OWLOntologyManager manager;
  private OWLDataFactory factory;
  private OWLOntology ontology;
  private TaxonomyPatternDetector detector;

  private static final String BASE_IRI = "http://example.org/test#";

  @BeforeEach
  void setUp() throws OWLOntologyCreationException {
    manager = OWLManager.createOWLOntologyManager();
    ontology = manager.createOntology(IRI.create(BASE_IRI + "ontology"));
    factory = manager.getOWLDataFactory();
    detector = new TaxonomyPatternDetector(ontology);
  }

  @Nested
  class PatternADetection {

    @Test
    void detectsPatternAWithUntypedIndividuals() {
      OWLNamedIndividual active = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Active"));
      OWLNamedIndividual inactive = factory.getOWLNamedIndividual(IRI.create(BASE_IRI + "Inactive"));

      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(active));
      manager.addAxiom(ontology, factory.getOWLDeclarationAxiom(inactive));

      OWLClassExpression oneOf = factory.getOWLObjectOneOf(active, inactive);

      Optional<TaxonomyInfo> result = detector.detect("status", oneOf);

