  private void setPropertiesWithCardinality(OWLObjectCardinalityRestriction ce) {
    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      objectPropertyNames.add(propertyName);

      final String propName = propertyName;
      RestrictionInfo.from(ce).ifPresent(info ->
          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));

      // Detect taxonomy patterns
      taxonomyDetector.detect(propertyName, ce.getFiller())
          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));

      if (ce.getFiller().isOWLClass()) {
        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
      }
    }
    propertyName = "";
  }

  private void setBooleanCombinationObjectProperties(OWLClassExpression expression,
      Set<OWLClassExpression> ranges,
      Set<OWLObjectProperty> properties) {
    if (propertyName.isEmpty()) {
      for (OWLObjectProperty property : properties) {
        propertyName = cleanName(nameResolver.resolve(property));
        objectPropertyNames.add(propertyName);
        for (OWLClassExpression range : ranges) {
          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }

      for (OWLDataProperty property : expression.getDataPropertiesInSignature()) {
        propertyName = cleanName(nameResolver.resolve(property));
        dataPropertyNames.add(propertyName);
        for (OWLClassExpression range : ranges) {
          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }
    } else {
      for (OWLClassExpression range : ranges) {
        Set<OWLClass> rangeClasses = range.getClassesInSignature();
        if (rangeClasses.size() != 1) {
          range.accept(this);
        } else if (!range.asOWLClass().equals(owlThing)) {
          // Range is tracked in objectPropertyRanges via visitor methods
        } else {
          logger.fine("Ignoring owl:Thing range " + propertyName);
        }
      }
    }
    propertyName = "";
  }

  private void setBooleanCombinationDataProperties(OWLDataRange expression,
      Set<OWLDataRange> ranges,
      Set<OWLDataProperty> properties) {
    if (propertyName.isEmpty()) {
      for (OWLDataProperty property : properties) {
        propertyName = cleanName(nameResolver.resolve(property));
        dataPropertyNames.add(propertyName);
        for (OWLDataRange range : ranges) {
          for (OWLDataProperty rangeProp : range.getDataPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }

      for (OWLObjectProperty property : expression.getObjectPropertiesInSignature()) {
        propertyName = cleanName(nameResolver.resolve(property));
        objectPropertyNames.add(propertyName);
        for (OWLDataRange range : ranges) {
          for (OWLObjectProperty rangeProp : range.getObjectPropertiesInSignature()) {
            if (nameResolver.resolve(rangeProp).equals(propertyName)) {
              range.accept(this);
            }
          }
        }
      }
    } else {
      for (OWLDataRange range : ranges) {
        Set<OWLDatatype> rangeDatatypes = range.getDatatypesInSignature();
        if (rangeDatatypes.size() != 1) {
          range.accept(this);
        } else if (!range.asOWLDatatype().asOWLClass().equals(owlThing)) {
          // Range is tracked in dataPropertyRanges via visitor methods
        } else {
          logger.fine("Ignoring owl:Thing range " + propertyName);
        }
      }
    }
    propertyName = "";
  }

  private void setDataPropertiesWithCardinality(OWLDataCardinalityRestriction ce) {
    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
      propertyName = cleanName(nameResolver.resolve(property));
      dataPropertyNames.add(propertyName);

      final String propName = propertyName;
      RestrictionInfo.from(ce).ifPresent(info ->
          restrictions.computeIfAbsent(propName, k -> new LinkedHashSet<>()).add(info));

      for (OWLDatatype datatype : ce.getDatatypesInSignature()) {
        dataPropertyRanges.put(propertyName, datatype);
      }
    }
    propertyName = "";
  }

  // Getters for type-safe storage (unmodifiable views)
  public Map<String, Set<RestrictionInfo>> getRestrictions() {
    return Collections.unmodifiableMap(restrictions);
  }

  public Multimap<String, OWLClass> getObjectPropertyRanges() {
    return Multimaps.unmodifiableMultimap(objectPropertyRanges);
  }

  public Multimap<String, OWLDatatype> getDataPropertyRanges() {
    return Multimaps.unmodifiableMultimap(dataPropertyRanges);
  }

  public Set<String> getObjectPropertyNames() {
    return Collections.unmodifiableSet(objectPropertyNames);
  }

  public Set<String> getDataPropertyNames() {
    return Collections.unmodifiableSet(dataPropertyNames);
  }

  public Map<String, TaxonomyInfo> getTaxonomyPatterns() {
    return Collections.unmodifiableMap(taxonomyPatterns);
  }

  public OWLOntology getOntology() {
    return onto;
  }

  private static String cleanName(String propertyName) {
    return Objects.requireNonNull(propertyName);
  }
