    72→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    73→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    74→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    75→ * </ul>
    76→ *
    77→ * <h2>Visitor Traversal Behavior</h2>
    78→ * <p>The visitor recursively processes class hierarchies:
    79→ * <ul>
    80→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    81→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    82→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    83→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    84→ * </ul>
    85→ *
    86→ * <h2>Thread Safety</h2>
    87→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    88→ * traversal and should not be shared between threads or reused for multiple traversals.
    89→ *
    90→ * @see RestrictionInfo
    91→ * @see PropertyNameResolver
    92→ */
    93→public class SchemaVisitor implements OWLObjectVisitor {
    94→
    95→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    96→
    97→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    98→  private final TaxonomyPatternDetector taxonomyDetector;
    99→  private final Set<OWLClass> processedClasses;
   100→  private final OWLClass cls;
   101→  private final OWLOntology onto;
   102→  String propertyName;
   103→  OWLClass owlThing;
   104→  Boolean range;
   105→
   106→
   107→  // Type-safe storage (private with unmodifiable getters)
   108→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   109→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   110→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   111→
   112→  // Property name tracking (minimal - just names, not full OWL objects)
   113→  private final Set<String> objectPropertyNames = new HashSet<>();
   114→  private final Set<String> dataPropertyNames = new HashSet<>();
   115→
   116→  // Taxonomy pattern tracking
   117→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   118→
   119→  /**
   120→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   121→   *
   122→   * @param visitedClass the OWL class to analyze for restrictions
   123→   * @param onto         the ontology containing the class and its axioms
   124→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   125→   *                     no information)
   126→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   127→   * @param range        whether this visitor is analyzing property ranges (typically false for
   128→   *                     initial call)
   129→   */
   130→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   131→      String propertyName, Boolean range) {
   132→    processedClasses = new HashSet<>();
   133→    this.cls = visitedClass;
   134→    this.onto = onto;
   135→    this.propertyName = propertyName;
   136→    this.owlThing = owlThing;
   137→    this.range = range;
   138→    this.taxonomyDetector = new TaxonomyPatternDetector(onto, nameResolver);
   139→  }
   140→
   141→  @Override
   142→  public void visit(OWLClass ce) {
   143→    if (!processedClasses.contains(ce)) {
   144→      processedClasses.add(ce);
   145→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   146→        ax.getSuperClass().accept(this);
   147→      }
   148→    }
   149→  }
   150→
   151→  @Override
   152→  public void visit(OWLObjectSomeValuesFrom ce) {
   153→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   154→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   155→      propertyName = cleanName(nameResolver.resolve(property));
   156→      objectPropertyNames.add(propertyName);
   157→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   158→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   159→
   160→      // Detect taxonomy patterns
   161→      taxonomyDetector.detect(propertyName, ce.getFiller())
   162→          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));
   163→    }
   164→
   165→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   166→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   167→        ce.getFiller() instanceof OWLObjectOneOf) {
   168→      ce.getFiller().accept(this);
   169→    } else {
   170→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   171→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   172→      } else {
   173→        logger.fine("Ignoring owl:Thing range " + propertyName);
   174→      }
   175→    }
   176→    propertyName = "";
   177→  }
   178→
   179→  @Override
   180→  public void visit(OWLObjectAllValuesFrom ce) {
