    46→/**
    47→ * Maps an OWL class to an OpenAPI Schema object.
    48→ *
    49→ * <p>This mapper analyzes an OWL class from the ontology and generates a corresponding
    50→ * OpenAPI 3.1 ObjectSchema with properties derived from:
    51→ * <ul>
    52→ *   <li><b>Data properties</b> - mapped to primitive schema types (string, integer, etc.)</li>
    53→ *   <li><b>Object properties</b> - mapped to $ref references or inline schemas</li>
    54→ *   <li><b>Taxonomy properties</b> - mapped to enum schemas based on named individuals</li>
    55→ * </ul>
    56→ *
    57→ * <h2>Processing Pipeline</h2>
    58→ * <pre>
    59→ * OWLClass → SchemaVisitors → Axiom Collection → Restriction Merging
    60→ *                                    ↓
    61→ *         ┌────────────────────────────────────────────┐
    62→ *         │                                            │
    63→ *         ▼                    ▼                       ▼
    64→ *   DataPropertyMapper   ObjectPropertyMapper   TaxonomyPropertyMapper
    65→ *         │                    │                       │
    66→ *         └────────────────────┴───────────────────────┘
    67→ *                              ↓
    68→ *                      OpenAPI ObjectSchema
    69→ * </pre>
    70→ *
    71→ * <h2>Annotation Filtering</h2>
    72→ * <p>Only axioms annotated with {@code apiLabel} matching the schema label from
    73→ * {@link MappingContext#getSchemaLabel()} are included in the generated schema.
    74→ *
    75→ * <h2>Thread Safety</h2>
    76→ * <p>This class is <b>not thread-safe</b>. Each instance should be used to map
    77→ * a single OWL class and then discarded.
    78→ *
    79→ * @see DataPropertyMapper
    80→ * @see ObjectPropertyMapper
    81→ * @see TaxonomyPropertyMapper
    82→ * @see SchemaVisitor
    83→ */
    84→public class ResourceSchemaMapper {
    85→
    86→  /**
    87→   * Holds paired SchemaVisitors for analyzing object and data property restrictions.
    88→   *
    89→   * @param objectPropertyVisitor visitor that collects object property restrictions
    90→   * @param dataPropertyVisitor visitor that collects data property restrictions
    91→   */
    92→  private record VisitorPair(SchemaVisitor objectPropertyVisitor, SchemaVisitor dataPropertyVisitor) {}
    93→
    94→  /**
    95→   * Holds categorized axiom collections for the analyzed class.
    96→   *
    97→   * @param taxonomy axioms referencing named individuals (enum values)
    98→   * @param subClass direct SubClassOf axioms for the analyzed class
    99→   * @param superClass inherited axioms from the class hierarchy
   100→   */
   101→  private record AxiomCollection(
   102→      List<OWLSubClassOfAxiom> taxonomy,
   103→      List<OWLSubClassOfAxiom> subClass,
   104→      List<OWLSubClassOfAxiom> superClass) {}
   105→  private static final Logger logger = Logger.getLogger(ResourceSchemaMapper.class.getName());
   106→  private final MappingContext context;
   107→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
   108→  private final String type;
   109→  private final OWLClass cls;
   110→  private final String classDescription;
   111→  private final String name;
   112→  private final Schema<?> schema;
   113→
   114→  public Schema<?> getSchema() {
   115→    return schema;
   116→  }
   117→
   118→  public String getName() {
   119→    return name;
   120→  }
   121→
   122→  public ResourceSchemaMapper(MappingContext context, OWLClass cls, String clsDescription) {
   123→    this.context = context;
   124→    this.cls = cls;
   125→    this.classDescription = clsDescription;
   126→    this.type = "object";
   127→    this.name = nameResolver.resolve(cls);
   128→    this.schema = createSchema(cls);
   129→  }
   130→
   131→  /**
   132→   * Creates the OpenAPI schema for the analyzed OWL class.
   133→   *
   134→   * <p>This method orchestrates the schema generation by:
   135→   * <ol>
   136→   *   <li>Initializing the base ObjectSchema with metadata</li>
   137→   *   <li>Creating visitors to traverse class restrictions</li>
   138→   *   <li>Collecting relevant axioms from the ontology</li>
   139→   *   <li>Visiting axioms to gather property restrictions</li>
   140→   *   <li>Processing data, object, and taxonomy properties</li>
   141→   * </ol>
   142→   *
   143→   * @param analyzedClass the OWL class to generate a schema for
   144→   * @return the generated OpenAPI Schema object
   145→   */
   146→  private Schema<?> createSchema(OWLClass analyzedClass) {
   147→    Schema<?> schema = initializeResourceSchema();
   148→
   149→    VisitorPair visitors = createSchemaVisitors(analyzedClass);
   150→    AxiomCollection axioms = collectRelevantAxioms(analyzedClass);
   151→
   152→    visitAxiomsWithVisitors(visitors, axioms);
   153→
   154→    Map<String, Set<RestrictionInfo>> restrictions = mergeVisitorRestrictions(visitors);
   155→
   156→    processDataProperties(schema, visitors.dataPropertyVisitor(), restrictions, axioms.subClass());
   157→    processObjectProperties(schema, visitors.objectPropertyVisitor(), restrictions);
   158→    processTaxonomyProperties(schema, axioms.taxonomy(), visitors, restrictions);
   159→
   160→    if (schema.getProperties() == null || schema.getProperties().isEmpty()) {
   161→      logMissingPropertiesWarning(analyzedClass, axioms);
   162→    }
   163→
   164→    return schema;
   165→  }
   166→
   167→  /**
   168→   * Creates and configures the base ObjectSchema with standard properties.
   169→   *
   170→   * @return a new ObjectSchema configured with name, type, description, and OpenAPI 3.1 spec version
   171→   */
   172→  private Schema<?> initializeResourceSchema() {
   173→    Schema<?> resourceSchema = new ObjectSchema();
   174→    resourceSchema.setSpecVersion(SpecVersion.V31);
   175→    resourceSchema.setName(this.name);
   176→    resourceSchema.setDescription(this.classDescription);
   177→    resourceSchema.setType(this.type);
   178→    resourceSchema.setAdditionalProperties(false);
   179→    resourceSchema.setTitle(getLabel(this.cls));
   180→    return resourceSchema;
   181→  }
   182→
   183→  /**
   184→   * Creates paired SchemaVisitors for analyzing object and data property restrictions.
   185→   *
   186→   * <p>Both visitors traverse the same class hierarchy but collect different types
   187→   * of restrictions:
   188→   * <ul>
   189→   *   <li>Object visitor: collects SomeValuesFrom, AllValuesFrom, cardinality on object properties</li>
   190→   *   <li>Data visitor: collects DataSomeValuesFrom, DataAllValuesFrom, cardinality on data properties</li>
   191→   * </ul>
   192→   *
   193→   * @param analyzedClass the OWL class to analyze
   194→   * @return a record containing both configured visitors
   195→   */
   196→  private VisitorPair createSchemaVisitors(OWLClass analyzedClass) {
   197→    OWLDataFactory dataFactory = context.getManager().getOWLDataFactory();
   198→    OWLClass owlThing = dataFactory.getOWLThing();
   199→    return new VisitorPair(
   200→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false),
   201→        new SchemaVisitor(analyzedClass, context.getOntology(), owlThing, "", false));
   202→  }
   203→
   204→  /**
   205→   * Collects all relevant axioms for the analyzed class from the ontology.
   206→   *
   207→   * <p>Gathers three categories of axioms:
   208→   * <ul>
   209→   *   <li><b>Taxonomy axioms</b>: SubClassOf axioms referencing named individuals (enum values)</li>
   210→   *   <li><b>SubClass axioms</b>: Direct SubClassOf axioms for the analyzed class</li>
   211→   *   <li><b>SuperClass axioms</b>: Inherited axioms from the class hierarchy</li>
   212→   * </ul>
   213→   *
   214→   * @param analyzedClass the OWL class to collect axioms for
   215→   * @return a record containing categorized axiom lists
   216→   */
   217→  private AxiomCollection collectRelevantAxioms(OWLClass analyzedClass) {
   218→    OWLOntology ontology = context.getOntology();
   219→    return new AxiomCollection(
   220→        getTaxonomyAxioms(analyzedClass),
   221→        ontology.subClassAxiomsForSubClass(analyzedClass).toList(),
   222→        getSuperClassAxioms(analyzedClass, null).toList());
   223→  }
   224→
   225→  /**
   226→   * Visits axioms with the appropriate schema visitors to collect restrictions.
   227→   *
   228→   * <p>For each axiom, the superclass expression is visited by the object property
   229→   * visitor if it contains object properties, and by the data property visitor if
   230→   * it contains data properties.
   231→   *
   232→   * <p>Taxonomy axioms are also visited to detect taxonomy patterns (A, B, C, D)
   233→   * via SchemaVisitor.detectTaxonomyPattern.
   234→   *
   235→   * @param visitors the visitor pair to use
   236→   * @param axioms the axiom collection to process
   237→   */
   238→  private void visitAxiomsWithVisitors(VisitorPair visitors, AxiomCollection axioms) {
   239→    String schemaLabel = context.getSchemaLabel();
   240→
   241→    // Filter axioms to only those annotated with the target apiLabel
   242→    // This allows multiple API schemas to be generated from the same ontology
   243→    axioms.subClass().stream()
   244→        .filter(axiom -> !axioms.taxonomy().contains(axiom))
   245→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   246→        .map(OWLSubClassOfAxiom::getSuperClass)
   247→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   248→
   249→    axioms.superClass().stream()
   250→        .map(OWLSubClassOfAxiom::getSuperClass)
   251→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   252→
   253→    // Also visit taxonomy axioms for pattern detection
   254→    // This enables detectTaxonomyPattern to be called for Pattern B individuals
   255→    axioms.taxonomy().stream()
   256→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
   257→        .map(OWLSubClassOfAxiom::getSuperClass)
   258→        .forEach(superClass -> visitSuperClass(superClass, visitors));
   259→  }
   260→
   261→  /**
   262→   * Visits a superclass expression with the appropriate visitors based on property types.
   263→   *
   264→   * @param superClass the class expression to visit
   265→   * @param visitors the visitor pair
   266→   */
   267→  private void visitSuperClass(OWLClassExpression superClass, VisitorPair visitors) {
   268→    if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
   269→      superClass.accept(visitors.objectPropertyVisitor());
   270→    }
   271→    if (!superClass.getDataPropertiesInSignature().isEmpty()) {
   272→      superClass.accept(visitors.dataPropertyVisitor());
   273→    }
   274→  }
   275→
   276→  /**
   277→   * Merges typed restrictions from both schema visitors into a unified map.
   278→   *
   279→   * <p>Combines restrictions keyed by property name. A single property may have
   280→   * multiple restrictions (e.g., both minCardinality and maxCardinality).
   281→   *
   282→   * @param visitors the visitor pair containing collected restrictions
   283→   * @return map of property name → set of RestrictionInfo for that property
   284→   */
   285→  private Map<String, Set<RestrictionInfo>> mergeVisitorRestrictions(VisitorPair visitors) {
   286→    Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   287→    Stream.of(visitors.objectPropertyVisitor(), visitors.dataPropertyVisitor())
   288→        .map(SchemaVisitor::getRestrictions)
   289→        .flatMap(map -> map.entrySet().stream())
   290→        .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
   291→            .addAll(entry.getValue()));
   292→    return restrictions;
   293→  }
   294→
   295→  /**
   296→   * Finds a data property in the ontology by its resolved name.
   297→   *
   298→   * @param propertyName the short-form property name (e.g., "firstName")
   299→   * @return the matching OWLDataProperty, or empty if not found
   300→   */
   301→  private Optional<OWLDataProperty> findDataProperty(String propertyName) {
   302→    return context.getOntology()
   303→        .getDataPropertiesInSignature().stream()
   304→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   305→        .findFirst();
   306→  }
   307→
   308→  /**
   309→   * Finds an object property in the ontology by its resolved name.
   310→   *
   311→   * @param propertyName the short-form property name (e.g., "hasAddress")
   312→   * @return the matching OWLObjectProperty, or empty if not found
   313→   */
   314→  private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
   315→    return context.getOntology()
   316→        .getObjectPropertiesInSignature().stream()
   317→        .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
   318→        .findFirst();
   319→  }
   320→
   321→  /**
   322→   * Extracts range type/class names for a property from multiple sources.
   323→   *
   324→   * <p>Ranges are collected from:
   325→   * <ol>
   326→   *   <li>The SchemaVisitor's property range multimap (from restriction fillers)</li>
   327→   *   <li>The RestrictionInfo objects themselves (via getRangeNames)</li>
   328→   * </ol>
   329→   *
   330→   * @param propertyName the property to extract ranges for
   331→   * @param rangesFromVisitor multimap of property → range classes/datatypes from visitor
   332→   * @param restrictions map of property → RestrictionInfo set
   333→   * @return deduplicated list of range type names
   334→   */
   335→  private List<String> extractPropertyRanges(
   336→      String propertyName,
   337→      Multimap<String, ? extends OWLEntity> rangesFromVisitor,
   338→      Map<String, Set<RestrictionInfo>> restrictions) {
   339→    List<String> ranges = new ArrayList<>();
   340→
   341→    // Extract from visitor's range multimap
   342→    rangesFromVisitor.get(propertyName).stream()
   343→        .map(nameResolver::resolve)
   344→        .forEach(ranges::add);
   345→
   346→    // Also extract from restrictions themselves
   347→    Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   348→    propertyRestrictions.stream()
   349→        .flatMap(r -> r.getRangeNames(nameResolver).stream())
   350→        .forEach(ranges::add);
   351→
   352→    // Remove duplicates to avoid treating single-range properties as multi-range
   353→    return ranges.stream().distinct().toList();
   354→  }
   355→
   356→  /**
   357→   * Extracts the example value for a data property from annotations.
   358→   *
   359→   * <p>Looks for skos:example annotations in two places (in order):
   360→   * <ol>
   361→   *   <li>On the SubClassOf axiom containing the property restriction</li>
   362→   *   <li>On the data property itself (as a default)</li>
   363→   * </ol>
   364→   *
   365→   * @param dataProperty the data property to find an example for
   366→   * @param subClassAxioms axioms that may contain restriction-level annotations
   367→   * @return the example value string, or null if none found
   368→   */
   369→  private String extractExampleValue(OWLDataProperty dataProperty, List<OWLSubClassOfAxiom> subClassAxioms) {
   370→    // First, look for a skos:example annotation on the restriction axiom itself
   371→    return subClassAxioms.stream()
   372→        .filter(axiom ->
   373→            axiom.getSuperClass() instanceof OWLDataRestriction restriction
   374→                && restriction.getProperty().asOWLDataProperty().getIRI().equals(dataProperty.getIRI()))
   375→        .map(axiom -> axiom.getAnnotations().stream()
   376→            .filter(annotation -> annotation.getProperty().getIRI().equals(OntologyConstants.SKOS_EXAMPLE))
   377→            .findFirst()
   378→            .flatMap(annotation -> annotation.mapLiteral(OWLLiteral::getLiteral)))
   379→        .flatMap(Optional::stream)
   380→        .findFirst()
   381→        // Fall back to the annotation on the data property itself
   382→        .orElse(OntologyUtil.defaultAnnotationsOf(dataProperty, context.getOntology())
   383→            .getOrDefault(OntologyConstants.SKOS_EXAMPLE.getShortForm(), null));
   384→  }
   385→
   386→  /**
   387→   * Processes all data properties and adds them to the schema.
   388→   *
   389→   * <p>For each data property discovered by the SchemaVisitor:
   390→   * <ol>
   391→   *   <li>Looks up the OWLDataProperty in the ontology</li>
   392→   *   <li>Extracts description, label, example, ranges, and enum values</li>
   393→   *   <li>Creates a DataPropertyMapper to generate the schema</li>
   394→   *   <li>Adds the property to the resource schema</li>
   395→   *   <li>Marks as required if restrictions indicate requiredness</li>
   396→   * </ol>
   397→   *
   398→   * @param schema the resource schema to add properties to
   399→   * @param dataVisitor visitor containing data property information
   400→   * @param restrictions merged restrictions map
   401→   * @param subClassAxioms axioms for extracting example annotations
   402→   */
   403→  private void processDataProperties(
   404→      Schema<?> schema,
   405→      SchemaVisitor dataVisitor,
   406→      Map<String, Set<RestrictionInfo>> restrictions,
   407→      List<OWLSubClassOfAxiom> subClassAxioms) {
   408→
   409→    Multimap<String, OWLDatatype> dataPropertyRanges = dataVisitor.getDataPropertyRanges();
   410→    Set<String> dataPropertyNames = dataVisitor.getDataPropertyNames();
   411→
   412→    for (String propertyName : dataPropertyNames) {
   413→      Optional<OWLDataProperty> dataPropertyOpt = findDataProperty(propertyName);
   414→      if (dataPropertyOpt.isEmpty()) {
   415→        continue;
   416→      }
   417→
   418→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   419→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   420→
   421→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   422→      String label = getLabel(dataProperty);
   423→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   424→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   425→      List<String> enumValues = propertyRestrictions.stream()
   426→          .flatMap(r -> r.getEnumValues().stream())
   427→          .toList();
   428→
   429→      DataPropertyMapper mapper = new DataPropertyMapper(
   430→          context.getConfig(),
   431→          nameResolver.resolve(dataProperty),
   432→          label,
   433→          propertyDescription,
   434→          exampleValue,
   435→          propertyRestrictions,
   436→          enumValues,
   437→          rangeTypes);
   438→
   439→      try {
   440→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   441→        if (mapper.isRequired()) {
   442→          schema.addRequiredItem(mapper.getName());
   443→        }
   444→      } catch (Exception e) {
   445→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   446→      }
   447→    }
   448→  }
   449→
   450→  /**
   451→   * Processes all object properties and adds them to the schema.
   452→   *
   453→   * <p>For each object property discovered by the SchemaVisitor:
   454→   * <ol>
   455→   *   <li>Looks up the OWLObjectProperty in the ontology</li>
   456→   *   <li>Extracts description, label, and range classes</li>
   457→   *   <li>Creates an ObjectPropertyMapper to generate the schema</li>
   458→   *   <li>Adds the property to the resource schema</li>
   459→   *   <li>Marks as required if restrictions indicate requiredness</li>
   460→   * </ol>
   461→   *
   462→   * @param schema the resource schema to add properties to
   463→   * @param objectVisitor visitor containing object property information
   464→   * @param restrictions merged restrictions map
   465→   */
   466→  private void processObjectProperties(
   467→      Schema<?> schema,
   468→      SchemaVisitor objectVisitor,
   469→      Map<String, Set<RestrictionInfo>> restrictions) {
   470→
   471→    Multimap<String, OWLClass> objectPropertyRanges = objectVisitor.getObjectPropertyRanges();
   472→    Set<String> objectPropertyNames = objectVisitor.getObjectPropertyNames();
   473→
   474→    for (String propertyName : objectPropertyNames) {
   475→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   476→      if (objectPropertyOpt.isEmpty()) {
   477→        continue;
   478→      }
   479→
   480→      OWLObjectProperty objectProperty = objectPropertyOpt.get();
   481→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   482→
   483→      String propertyDescription = OntologyUtil.getDescription(objectProperty, context.getOntology());
   484→      String propertyLabel = getLabel(objectProperty);
   485→      List<String> rangeClasses = extractPropertyRanges(propertyName, objectPropertyRanges, restrictions);
   486→
   487→      ObjectPropertyMapper mapper = new ObjectPropertyMapper(
   488→          context, propertyName, propertyLabel, propertyDescription, propertyRestrictions, rangeClasses);
   489→
   490→      schema.addProperty(mapper.getName(), mapper.getSchema());
   491→      if (mapper.isRequired()) {
   492→        schema.addRequiredItem(mapper.getName());
   493→      }
   494→    }
   495→  }
   496→
   497→  /**
   498→   * Processes taxonomy axioms and adds enum properties to the schema.
   499→   *
   500→   * <p>This method first checks for taxonomy patterns detected by SchemaVisitor
   501→   * (patterns A, B, C, D) and uses TaxonomyPatternMapper for those. Falls back
   502→   * to existing logic for class-based taxonomies that weren't detected as patterns.
   503→   *
   504→   * <p>Supported patterns:
   505→   * <ul>
   506→   *   <li><b>Pattern A</b>: Inline enum with untyped individuals (owl:oneOf)</li>
   507→   *   <li><b>Pattern B</b>: Typed individuals with metadata (owl:oneOf)</li>
   508→   *   <li><b>Pattern C</b>: Class-based taxonomy (extensible)</li>
   509→   *   <li><b>Pattern D</b>: SKOS taxonomy (FHIR-compatible)</li>
   510→   *   <li><b>Legacy</b>: Direct individual references or class-based lookup</li>
   511→   * </ul>
   512→   *
   513→   * @param schema the resource schema to add taxonomy properties to
   514→   * @param taxonomyAxioms axioms identified as taxonomy definitions
   515→   * @param visitors the visitor pair containing detected taxonomy patterns
   516→   * @param restrictions merged restrictions map
   517→   */
   518→  private void processTaxonomyProperties(
   519→      Schema<?> schema,
   520→      List<OWLSubClassOfAxiom> taxonomyAxioms,
   521→      VisitorPair visitors,
   522→      Map<String, Set<RestrictionInfo>> restrictions) {
   523→
   524→    // First, process detected taxonomy patterns from SchemaVisitor
   525→    Set<String> processedProperties = new HashSet<>();
   526→    Map<String, TaxonomyInfo> taxonomyPatterns = extractTaxonomyPatterns(visitors);
   527→
   528→    for (Map.Entry<String, TaxonomyInfo> entry : taxonomyPatterns.entrySet()) {
   529→      String propertyName = entry.getKey();
   530→      TaxonomyInfo info = entry.getValue();
   531→
   532→      if (info.pattern() == TaxonomyPattern.NONE) {
   533→        continue;
   534→      }
   535→
   536→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   537→      Optional<OWLObjectProperty> objectPropertyOpt = findObjectProperty(propertyName);
   538→
   539→      String description = objectPropertyOpt
   540→          .map(prop -> OntologyUtil.getDescription(prop, context.getOntology()))
   541→          .orElse("");
   542→      String label = objectPropertyOpt
   543→          .map(this::getLabel)
   544→          .orElse(propertyName);
   545→
   546→      TaxonomyPatternMapper mapper = new TaxonomyPatternMapper(
   547→          context, info, propertyRestrictions, description, label);
   548→
   549→      schema.addProperty(mapper.getName(), mapper.getSchema());
   550→      if (mapper.isRequired()) {
   551→        schema.addRequiredItem(mapper.getName());
   552→      }
   553→
   554→      processedProperties.add(propertyName);
   555→    }
   556→
   557→    // Fall back to legacy processing for taxonomy axioms not covered by pattern detection
   558→    Set<OWLObjectProperty> taxonomyPropertyNames = taxonomyAxioms.stream()
   559→        .map(OWLSubClassOfAxiom::getSuperClass)
   560→        .flatMap(superCls -> superCls.getObjectPropertiesInSignature().stream())
   561→        .filter(prop -> !processedProperties.contains(nameResolver.resolve(prop)))
   562→        .collect(Collectors.toSet());
   563→
   564→    for (OWLObjectProperty taxonomyProperty : taxonomyPropertyNames) {
   565→      for (OWLSubClassOfAxiom axiom : taxonomyAxioms) {
   566→        OWLClassExpression superCls = axiom.getSuperClass();
   567→
   568→        for (OWLObjectProperty objectProperty : superCls.getObjectPropertiesInSignature()) {
   569→          if (!objectProperty.equals(taxonomyProperty)) {
   570→            continue;
   571→          }
   572→
   573→          Set<RestrictionInfo> taxonomyRestrictions = new LinkedHashSet<>();
   574→          RestrictionInfo.from(superCls).ifPresent(taxonomyRestrictions::add);
   575→
   576→          // Taxonomy detection: check if axiom references named individuals directly
   577→          Set<OWLNamedIndividual> individualsInSignature = superCls.getIndividualsInSignature();
   578→
   579→          if (!individualsInSignature.isEmpty()) {
   580→            // Direct individual reference - use individual labels as enum values
   581→            addTaxonomyPropertyToSchema(schema,
   582→                nameResolver.resolve(taxonomyProperty),
   583→                OntologyUtil.getDescription(cls, context.getOntology()),
   584→                getLabel(taxonomyProperty),
   585→                individualsInSignature.stream().map(this::getLabel).toList(),
   586→                taxonomyRestrictions);
   587→          } else {
   588→            // Indirect reference via class - look up individuals belonging to the class
   589→            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
   590→              List<OWLNamedIndividual> individuals = EntitySearcher
   591→                  .getIndividuals(taxonomyClass, context.getOntology())
   592→                  .flatMap(Narrow.to(OWLNamedIndividual.class))
   593→                  .toList();
   594→
   595→              addTaxonomyPropertyToSchema(schema,
   596→                  taxonomyName(nameResolver.resolve(taxonomyClass)),
   597→                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
   598→                  getLabel(taxonomyClass),
   599→                  individuals.stream().map(this::getLabel).toList(),
   600→                  taxonomyRestrictions);
   601→            }
   602→          }
   603→        }
   604→      }
   605→    }
   606→  }
   607→
   608→  /**
   609→   * Extracts taxonomy patterns from both schema visitors.
   610→   *
   611→   * @param visitors the visitor pair
   612→   * @return map of property name to TaxonomyInfo
   613→   */
   614→  private Map<String, TaxonomyInfo> extractTaxonomyPatterns(VisitorPair visitors) {
   615→    Map<String, TaxonomyInfo> patterns = new HashMap<>();
   616→    patterns.putAll(visitors.objectPropertyVisitor().getTaxonomyPatterns());
   617→    patterns.putAll(visitors.dataPropertyVisitor().getTaxonomyPatterns());
   618→    return patterns;
   619→  }
   620→
   621→  /**
   622→   * Adds a taxonomy property to the schema.
   623→   *
   624→   * @param schema the schema to add the property to
   625→   * @param name the property name
   626→   * @param description the property description
   627→   * @param label the property label
   628→   * @param enumValues the list of allowed enum values
   629→   * @param restrictions the restrictions for this property
   630→   */
