   646→  /**
   647→   * Logs a warning when no properties were found for a class.
   648→   *
   649→   * <p>This typically indicates that the ontology is missing apiLabel annotations
   650→   * on the property restrictions, or that the schema label doesn't match.
   651→   *
   652→   * @param analyzedClass the class that had no mappable properties
   653→   * @param axioms all collected axioms (for diagnostic output)
   654→   */
   655→  private void logMissingPropertiesWarning(OWLClass analyzedClass, AxiomCollection axioms) {
   656→    logger.warning("No properties with " + OntologyConstants.apiLabel
   657→        + " annotation found for: " + analyzedClass);
   658→
   659→    List<OWLSubClassOfAxiom> allAxioms = Stream.of(axioms.superClass(), axioms.subClass(), axioms.taxonomy())
   660→        .flatMap(Collection::stream)
   661→        .toList();
   662→
   663→    if (!allAxioms.isEmpty()) {
   664→      allAxioms.stream()
   665→          .map(axiom -> axiom.getSuperClass().toString())
   666→          .forEach(s -> logger.warning("\tPossible property: " + s));
   667→    }
   668→  }
