   703→  private Stream<OWLSubClassOfAxiom> getSuperClassAxioms(OWLClass analyzedClass,
   704→                                                         @Nullable Set<OWLClass> ignoreClasses) {
   705→    final Set<OWLClass> processedClasses = Optional.ofNullable(ignoreClasses).orElse(new HashSet<OWLClass>());
   706→    final String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   707→    return context.getOntology().subClassAxiomsForSubClass(analyzedClass)
   708→        .filter(WithAnnotation.of(OntologyConstants.apiLabel, context.getSchemaLabel()))
   709→        .map(OWLSubClassOfAxiom::getSuperClass).filter(OWLClassExpression::isOWLClass).map(AsOWLClass::asOWLClass)
   710→        .filter(Predicate.not(processedClasses::contains)).peek(processedClasses::add) // side effect
   711→        .flatMap(context.getOntology()::subClassAxiomsForSubClass).flatMap(owlSubClassOfAxiom -> {
   712→          final OWLClassExpression superClass = owlSubClassOfAxiom.getSuperClass();
   713→          final List<OWLSubClassOfAxiom> superClassAxioms = new ArrayList<>();
   714→          if (superClass.isOWLClass()) {
   715→            getSuperClassAxioms(superClass.asOWLClass(), processedClasses).forEach(superClassAxioms::add);
   716→          }
   717→          if (owlSubClassOfAxiom.annotations()
   718→              .anyMatch(owlAnnotation -> owlAnnotation.getValue().toString().equals(schemaAnnotation))) {
   719→            superClassAxioms.add(owlSubClassOfAxiom);
   720→          }
   721→          return superClassAxioms.stream();
   722→        });
   723→  }
