  // Filter axioms to only those annotated with the target apiLabel
  // This allows multiple API schemas to be generated from the same ontology
  axioms.subClass().stream()
      .filter(axiom -> !axioms.taxonomy().contains(axiom))
      .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
      .map(OWLSubClassOfAxiom::getSuperClass)
      .forEach(superClass -> visitSuperClass(superClass, visitors));

  axioms.superClass().stream()
      .map(OWLSubClassOfAxiom::getSuperClass)
      .forEach(superClass -> visitSuperClass(superClass, visitors));

  // Also visit taxonomy axioms for pattern detection
  // This enables detectTaxonomyPattern to be called for Pattern B individuals
  axioms.taxonomy().stream()
      .filter(WithAnnotation.of(OntologyConstants.apiLabel, schemaLabel))
      .map(OWLSubClassOfAxiom::getSuperClass)
      .forEach(superClass -> visitSuperClass(superClass, visitors));
}

/**
 * Visits a superclass expression with the appropriate visitors based on property types.
 *
 * @param superClass the class expression to visit
 * @param visitors the visitor pair
 */
private void visitSuperClass(OWLClassExpression superClass, VisitorPair visitors) {
  if (!superClass.getObjectPropertiesInSignature().isEmpty()) {
    superClass.accept(visitors.objectPropertyVisitor());
  }
  if (!superClass.getDataPropertiesInSignature().isEmpty()) {
    superClass.accept(visitors.dataPropertyVisitor());
  }
}

/**
 * Merges typed restrictions from both schema visitors into a unified map.
 *
 * <p>Combines restrictions keyed by property name. A single property may have
 * multiple restrictions (e.g., both minCardinality and maxCardinality).
 *
 * @param visitors the visitor pair containing collected restrictions
 * @return map of property name → set of RestrictionInfo for that property
 */
private Map<String, Set<RestrictionInfo>> mergeVisitorRestrictions(VisitorPair visitors) {
  Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
  Stream.of(visitors.objectPropertyVisitor(), visitors.dataPropertyVisitor())
      .map(SchemaVisitor::getRestrictions)
      .flatMap(map -> map.entrySet().stream())
      .forEach(entry -> restrictions.computeIfAbsent(entry.getKey(), k -> new LinkedHashSet<>())
          .addAll(entry.getValue()));
  return restrictions;
}

/**
 * Finds a data property in the ontology by its resolved name.
 *
 * @param propertyName the short-form property name (e.g., "firstName")
 * @return the matching OWLDataProperty, or empty if not found
 */
private Optional<OWLDataProperty> findDataProperty(String propertyName) {
  return context.getOntology()
      .getDataPropertiesInSignature().stream()
      .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
      .findFirst();
}

/**
 * Finds an object property in the ontology by its resolved name.
 *
 * @param propertyName the short-form property name (e.g., "hasAddress")
 * @return the matching OWLObjectProperty, or empty if not found
 */
private Optional<OWLObjectProperty> findObjectProperty(String propertyName) {
  return context.getOntology()
      .getObjectPropertiesInSignature().stream()
      .filter(prop -> nameResolver.resolve(prop).equals(propertyName))
      .findFirst();
}

