   418→      OWLDataProperty dataProperty = dataPropertyOpt.get();
   419→      Set<RestrictionInfo> propertyRestrictions = restrictions.getOrDefault(propertyName, Set.of());
   420→
   421→      String propertyDescription = OntologyUtil.getDescription(dataProperty, context.getOntology());
   422→      String label = getLabel(dataProperty);
   423→      String exampleValue = extractExampleValue(dataProperty, subClassAxioms);
   424→      List<String> rangeTypes = extractPropertyRanges(propertyName, dataPropertyRanges, restrictions);
   425→      List<String> enumValues = propertyRestrictions.stream()
   426→          .flatMap(r -> r.getEnumValues().stream())
   427→          .toList();
   428→
   429→      DataPropertyMapper mapper = new DataPropertyMapper(
   430→          context.getConfig(),
   431→          nameResolver.resolve(dataProperty),
   432→          label,
   433→          propertyDescription,
   434→          exampleValue,
   435→          propertyRestrictions,
   436→          enumValues,
   437→          rangeTypes);
   438→
   439→      try {
   440→        schema.addProperty(mapper.getName(), mapper.getSchemaByDataProperty());
   441→        if (mapper.isRequired()) {
   442→          schema.addRequiredItem(mapper.getName());
   443→        }
   444→      } catch (Exception e) {
   445→        throw new RuntimeException("Error when processing data property " + mapper.getName(), e);
   446→      }
